Add a WebSocket registry to the nexus AppState for inference subscribers.

In hex-nexus/src/lib.rs (or wherever AppState is defined), add:

```rust
use tokio::sync::broadcast;

/// Push channel for inference task dispatch.
/// Receivers: connected `hex inference watch` processes.
pub type InferenceTxBus = broadcast::Sender<InferenceTaskPush>;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct InferenceTaskPush {
    pub id: String,
    pub workplan_id: String,
    pub task_id: String,
    pub phase: String,
    pub prompt: String,
    pub role: String,
}
```

Add `inference_tx: InferenceTxBus` to AppState. Initialize in `build_app()` with `broadcast::channel(64)`. The STDB subscription handler fires `inference_tx.send(push)` when a new Pending inference_task row arrives.

Create hex-nexus/src/routes/inference_ws.rs:

```rust
use axum::{
    extract::{ws::{WebSocket, WebSocketUpgrade, Message}, State},
    response::IntoResponse,
};
use crate::{AppState, InferenceTaskPush};

pub async fn ws_inference_handler(
    ws: WebSocketUpgrade,
    State(state): State<AppState>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_inference_ws(socket, state))
}

async fn handle_inference_ws(mut socket: WebSocket, state: AppState) {
    let mut rx = state.inference_tx.subscribe();
    loop {
        tokio::select! {
            Ok(push) = rx.recv() => {
                let json = serde_json::to_string(&push).unwrap_or_default();
                if socket.send(Message::Text(json)).await.is_err() {
                    break; // client disconnected
                }
            }
            Some(Ok(Message::Close(_))) = socket.recv() => break,
            else => break,
        }
    }
}
```

Register in the router (find where other routes are registered, e.g. src/routes/mod.rs or lib.rs):
```rust
.route("/ws/inference", get(inference_ws::ws_inference_handler))
```

In hex-nexus/src/orchestration/workplan_executor.rs, in the `use_path_b` branch:

REPLACE:
```rust
// Write task to HexFlo memory queue
let queue_id = uuid::Uuid::new_v4().to_string();
let key = format!("inference:queue:{}", queue_id);
let payload = serde_json::json!({
    "id": queue_id,
    "task_id": task.id,
    "workplan_id": &execution.feature,
    "prompt": prompt_text,
    "role": role,
    "status": "Pending",
    "created_at": now,
});
hexflo.memory_store(&key, &payload.to_string(), "global").await?;
```

WITH:
```rust
// Write task to STDB inference_task table (ADR-2604011200)
let queue_id = uuid::Uuid::new_v4().to_string();
let phase_name = current_phase.name.as_deref().unwrap_or("unknown");
state.inference_task_create(
