Note: `state` is the IStatePort — it must be threaded into the executor. Check whether executor already holds a reference to AppState or needs to receive the state port as a parameter. If needed, add `state: Arc<dyn IStatePort>` to the ExecutionContext struct.

In workplan_executor.rs, replace the 5-second polling loop that reads hexflo_memory for task completion:

REPLACE:
```rust
loop {
    tokio::time::sleep(Duration::from_secs(5)).await;
    let val = hexflo.memory_retrieve(&key).await
        .ok().flatten()
        .and_then(|s| serde_json::from_str::<Value>(&s).ok())
        .unwrap_or_default();
    let status = val["status"].as_str().unwrap_or("");
    if status == "Completed" { break; }
    if status == "Failed" { return Err("task failed".into()); }
    elapsed += 5;
    if elapsed > timeout_secs { return Err("timeout".into()); }
}
```

WITH:
```rust
// Poll STDB inference_task for completion (subscribe-based would be ideal,
// but polling the STDB row is still far cheaper than memory key polling
// since STDB rows are indexed and queryable)
loop {
    tokio::time::sleep(Duration::from_secs(2)).await;
    match state.inference_task_get(&queue_id).await {
        Ok(Some(task)) => match task.status.as_str() {
            "Completed" => break,
            "Failed" => return Err(format!("inference task failed: {}", task.error)),
            _ => {},
        },
        Ok(None) => {},
        Err(e) => tracing::warn!("inference_task_get error: {}", e),
    }
    elapsed += 2;
    if elapsed > timeout_secs {
        let _ = state.inference_task_fail(&queue_id, "executor timeout", &chrono::Utc::now().to_rfc3339()).await;
        return Err("inference task timeout".into());
    }
}
```

